import{_ as i,o as a,c as t,ag as l}from"./chunks/framework.ePeAWSvT.js";const d=JSON.parse('{"title":"COURS : LA PNEUMONIE","description":"","frontmatter":{},"headers":[],"relativePath":"matieres/sante/cours/pneumonie-neuro.md","filePath":"matieres/sante/cours/pneumonie-neuro.md"}'),s={name:"matieres/sante/cours/pneumonie-neuro.md"};function n(r,e,o,u,c,m){return a(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="cours-la-pneumonie" tabindex="-1">COURS : LA PNEUMONIE <a class="header-anchor" href="#cours-la-pneumonie" aria-label="Permalink to &quot;COURS : LA PNEUMONIE&quot;">​</a></h1><h2 id="_1️⃣-definition" tabindex="-1">1️⃣ Définition <a class="header-anchor" href="#_1️⃣-definition" aria-label="Permalink to &quot;1️⃣ Définition&quot;">​</a></h2><p>La pneumonie est une <strong>infection aiguë des poumons</strong> qui provoque une inflammation des alvéoles pulmonaires.</p><p>Ces alvéoles peuvent se remplir de <strong>liquide ou de pus</strong>, ce qui rend la respiration difficile.</p><hr><h2 id="_2️⃣-causes" tabindex="-1">2️⃣ Causes <a class="header-anchor" href="#_2️⃣-causes" aria-label="Permalink to &quot;2️⃣ Causes&quot;">​</a></h2><p>La pneumonie peut être causée par :</p><ul><li>bactéries (cause la plus fréquente)</li><li>virus</li><li>champignons</li><li>inhalation de substances toxiques</li></ul><p>Les bactéries les plus fréquentes :</p><ul><li>Streptococcus pneumoniae</li><li>Haemophilus influenzae</li></ul><hr><h2 id="_3️⃣-facteurs-de-risque" tabindex="-1">3️⃣ Facteurs de risque <a class="header-anchor" href="#_3️⃣-facteurs-de-risque" aria-label="Permalink to &quot;3️⃣ Facteurs de risque&quot;">​</a></h2><ul><li>âge avancé</li><li>tabagisme</li><li>maladies chroniques</li><li>système immunitaire affaibli</li><li>hospitalisation prolongée</li></ul><hr><h2 id="_4️⃣-symptomes" tabindex="-1">4️⃣ Symptômes <a class="header-anchor" href="#_4️⃣-symptomes" aria-label="Permalink to &quot;4️⃣ Symptômes&quot;">​</a></h2><ul><li>fièvre</li><li>toux avec expectoration</li><li>essoufflement</li><li>douleur thoracique</li><li>fatigue</li><li>frissons</li></ul><hr><h2 id="_5️⃣-diagnostic" tabindex="-1">5️⃣ Diagnostic <a class="header-anchor" href="#_5️⃣-diagnostic" aria-label="Permalink to &quot;5️⃣ Diagnostic&quot;">​</a></h2><ul><li>examen clinique</li><li>radiographie pulmonaire</li><li>analyses sanguines</li><li>analyse des expectorations</li></ul><hr><h2 id="_6️⃣-traitement" tabindex="-1">6️⃣ Traitement <a class="header-anchor" href="#_6️⃣-traitement" aria-label="Permalink to &quot;6️⃣ Traitement&quot;">​</a></h2><ul><li>antibiotiques (si bactérienne)</li><li>antipyrétiques</li><li>oxygénothérapie si nécessaire</li><li>repos et hydratation</li></ul>',22)])])}const h=i(s,[["render",n]]);export{d as __pageData,h as default};
